    @pytest.mark.slow
    def test_fragmentation_and_vocab(self):
        corpus = GSGE_Corpus()
        corpus.build_corpus(
            self.subset,
            min_size=1,
            max_size=15,
            method='default',
            fragment_mol_fn=CUSTOM_fragment_mol,
            convert=True,
            fragmented=False
        )

        self.assertEqual(corpus.core_counter, self.expected_core_counter)
        self.assertEqual(corpus.num_fragments, self.expected_num_fragments)

        actual_fragment_smiles = [v.canonsmiles for k, v in corpus.vocab_fragments.items()]
        self.assertCountEqual(actual_fragment_smiles, self.expected_fragment_smiles)

